const startTime = Date.now();
const text = $input.item.json.body.text;
const charCount = text.length;

// Token estimation: ~3.5 characters per token for average text
const estimatedTokens = Math.ceil(charCount / 3.5);

return [{
  json: {
    ...($input.item.json),
    _startTime: startTime,
    _inputChars: charCount,
    _estimatedInputTokens: estimatedTokens
  }
}];

const text = $input.item.json.body.text;
const charCount = text.length;

// Safe character limits (~1000-1200 tokens per chunk)
// Ensures both prompt and response fit within context window.
const SAFE_CHARS = 5000; 
const CHARS_PER_CHUNK = 5000; 

if (charCount <= SAFE_CHARS) {
  return [{
    json: {
      needs_chunking: false,
      chunks: [text],
      chunk_count: 1,
      total_chars: charCount,
      _startTime: $input.item.json._startTime,
      _inputChars: $input.item.json._inputChars,
      _estimatedInputTokens: $input.item.json._estimatedInputTokens
    }
  }];
} else {
  const chunkCount = Math.max(2, Math.ceil(charCount / CHARS_PER_CHUNK));
  const lines = text.split('\n');
  const chunkSize = Math.ceil(lines.length / chunkCount);

  const chunks = [];
  for (let i = 0; i < chunkCount; i++) {
    const start = i * chunkSize;
    const end = Math.min(start + chunkSize, lines.length);
    const chunk = lines.slice(start, end).join('\n').trim();
    if (chunk.length > 0) chunks.push(chunk);
  }

  return [{
    json: {
      needs_chunking: true,
      chunks: chunks,
      chunk_count: chunks.length,
      total_chars: charCount,
      _startTime: $input.item.json._startTime,
      _inputChars: $input.item.json._inputChars,
      _estimatedInputTokens: $input.item.json._estimatedInputTokens
    }
  }];
}

