const item = $input.item.json;
const chunks = item.chunks;

return chunks.map((chunk, i) => ({
  json: {
    chunk_index: i + 1,
    total_chunks: chunks.length,
    content: chunk
  }
}));

const items = $input.all();

const combined = items
  .map((item, i) => `### Section ${i + 1} Summary\n${item.json.choices[0].message.content}`)
  .join('\n\n');

return [{ json: { combined_summaries: combined } }];

