const item = $input.item.json;

// Extract critique from the Grill/Critical Review node
const grillContent = item.choices[0].message.content;

// Usage info from LLM response (if available)
const grillUsage = item.usage || {};

const endTime = Date.now();

// Retrieve start time from the Start Timer node
let startTime;
try {
  startTime = $('Start Timer').item.json._startTime;
} catch(e) {
  startTime = endTime - 1000; // fallback
}

let inputChars, estimatedInputTokens;
try {
  inputChars = $('Start Timer').item.json._inputChars;
  estimatedInputTokens = $('Start Timer').item.json._estimatedInputTokens;
} catch(e) {
  inputChars = 0;
  estimatedInputTokens = 0;
}

const durationMs = endTime - startTime;
const durationSec = (durationMs / 1000).toFixed(1);
const durationMin = (durationMs / 60000).toFixed(2);

// Token estimation based on output text length
const summaryContent = $('Merge Branches').item.json.choices
  ? $('Merge Branches').item.json.choices[0].message.content
  : '';
const estimatedOutputTokens = Math.ceil((summaryContent.length + grillContent.length) / 4);
const totalEstimatedTokens = estimatedInputTokens + estimatedOutputTokens;

// Actual usage info (if LM Studio returns it)
let actualUsage = '';
if (grillUsage.total_tokens) {
  actualUsage = `\nActual Grill Tokens: ${grillUsage.total_tokens} (prompt: ${grillUsage.prompt_tokens}, completion: ${grillUsage.completion_tokens})`;
}

return [{
  json: {
    summary: summaryContent,
    critique: grillContent,
    stats: {
      processing_time_seconds: parseFloat(durationSec),
      processing_time_minutes: parseFloat(durationMin),
      input_characters: inputChars,
      estimated_input_tokens: estimatedInputTokens,
      estimated_output_tokens: estimatedOutputTokens,
      estimated_total_tokens: totalEstimatedTokens
    },
    stats_text: `⏱️ Processing Time: ${durationSec}s (${durationMin} min) | 📝 Input: ${inputChars} chars (~${estimatedInputTokens} tokens) | 📤 Output: ~${estimatedOutputTokens} tokens | 🔢 Total: ~${totalEstimatedTokens} tokens${actualUsage}`
  }
}];

